sql:
SELECT procedure_id, label, short_description
FROM procedures
WHERE status = 'completed' OR status = 'cancelled';

SELECT procedure_id
     FROM procedures
     ORDER BY procedure_id ASC;

SELECT procedure_id, COUNT(*) 
FROM reminders 
GROUP BY procedure_id;

SELECT short_description
FROM procedures
WHERE procedure_id = 1;

SELECT procedure_id, slice_name, alias, label, min_value, max_value, must_support, is_modifier, is_summary, type, short_description, definition, comments, requirements, default_value, procedure_date, patient_id, performer_id, status, location, duration, outcome, created_at, updated_at
FROM procedures
WHERE procedure_id = (SELECT MAX(procedure_id) FROM procedures);

SELECT 
  (SELECT reminder_text FROM reminders WHERE is_completed = 0 ORDER BY reminder_date ASC LIMIT 1) AS 'Earliest Reminder',
  (SELECT reminder_text FROM reminders WHERE is_completed = 0 ORDER BY reminder_date DESC LIMIT 1) AS 'Latest Reminder';

SELECT procedure_id, COUNT(access_id) AS TotalAccessLogs
FROM access_logs
GROUP BY procedure_id;
